import React, { useState, useEffect } from 'react';
import { Table, Badge, Spinner, Alert } from 'react-bootstrap';
import { History, Download, FileText } from 'lucide-react';
import { getVersionHistory, downloadDocument } from '../api';
import { toast } from 'react-toastify';
import './VersionHistory.css';

const VersionHistory = ({ documentId }) => {
  const [versions, setVersions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    loadVersionHistory();
  }, [documentId]);

  const loadVersionHistory = async () => {
    setLoading(true);
    setError(null);
    try {
      // Remove 'DOC' prefix if present
      const cleanId = typeof documentId === 'string' 
        ? documentId.replace('DOC', '') 
        : documentId;
      
      const response = await getVersionHistory(cleanId);
      
      if (response.data && response.data.data) {
        // Map versions and set uploadedBy to "HR User" instead of "System"
        const mappedVersions = response.data.data.map(version => ({
          ...version,
          uploadedBy: version.uploadedBy === 'System' ? 'HR User' : version.uploadedBy
        }));
        setVersions(mappedVersions);
      } else {
        setVersions([]);
      }
    } catch (err) {
      console.error('Error loading version history:', err);
      setError('Failed to load version history');
      setVersions([]);
    } finally {
      setLoading(false);
    }
  };

  const handleDownloadVersion = async (version) => {
    try {
      const response = await downloadDocument(version.documentId);
      const blob = response.data instanceof Blob 
        ? response.data 
        : new Blob([response.data], { type: response.headers?.['content-type'] });
      
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = version.fileName || `document_v${version.version}`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
      
      toast.success('Version downloaded successfully', {
        position: 'top-right',
        autoClose: 3000
      });
    } catch (error) {
      console.error('Error downloading version:', error);
      toast.error('Failed to download version', {
        position: 'top-right',
        autoClose: 3000
      });
    }
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    const date = new Date(dateString);
    return date.toLocaleString('en-IN', {
      year: 'numeric',
      month: 'short',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit'
    });
  };

  if (loading) {
    return (
      <div className="text-center py-4">
        <Spinner animation="border" variant="primary" />
        <p className="mt-2 text-muted">Loading version history...</p>
      </div>
    );
  }

  if (error) {
    return (
      <Alert variant="danger">
        <Alert.Heading>Error</Alert.Heading>
        <p>{error}</p>
      </Alert>
    );
  }

  if (versions.length === 0) {
    return (
      <div className="text-center py-4">
        <History size={48} className="text-muted mb-3" />
        <p className="text-muted">No version history available for this document.</p>
      </div>
    );
  }

  return (
    <div className="version-history-container">
      <div className="mb-3">
        <h6 className="d-flex align-items-center">
          <History className="me-2" size={20} />
          Version History
        </h6>
        <small className="text-muted">
          Total Versions: {versions.length}
        </small>
      </div>

      <Table hover responsive className="version-history-table">
        <thead>
          <tr>
            <th>Version</th>
            <th>File Name</th>
            <th>Uploaded By</th>
            <th>Upload Date</th>
            <th>Reason</th>
            <th className="text-center">Actions</th>
          </tr>
        </thead>
        <tbody>
          {versions.map((version, index) => (
            <tr key={version.id || index}>
              <td>
                {index === 0 ? (
                  <Badge bg="primary" className="px-3 py-2">
                    v{version.version} (Current)
                  </Badge>
                ) : (
                  <Badge bg="secondary" className="px-3 py-2">
                    v{version.version}
                  </Badge>
                )}
              </td>
              <td>
                <div className="d-flex align-items-center">
                  <FileText size={16} className="me-2 text-primary" />
                  <span className="text-truncate" style={{ maxWidth: '300px' }}>
                    {version.fileName || 'N/A'}
                  </span>
                </div>
              </td>
              <td>
                <strong>{version.uploadedBy || 'HR User'}</strong>
              </td>
              <td>
                <small>{formatDate(version.uploadDate)}</small>
              </td>
              <td>
                <small className="text-muted">
                  {version.reason || 'Initial upload'}
                </small>
              </td>
              <td className="text-center">
                <button
                  className="btn btn-sm btn-outline-primary"
                  onClick={() => handleDownloadVersion(version)}
                  title="Download this version"
                >
                  <Download size={16} />
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </Table>

      <div className="mt-3">
        <small className="text-muted">
          <strong>Note:</strong> Each version represents a different file upload. 
          The current version is marked with a blue badge.
        </small>
      </div>
    </div>
  );
};

export default VersionHistory;
